import{_ as i,o as a,c as e,ai as r}from"./chunks/framework.CaiDwmc7.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"04 Визуальный язык/UI UX/ТЗ на UI UX.md","filePath":"04 Визуальный язык/UI UX/ТЗ на UI UX.md"}'),t={name:"04 Визуальный язык/UI UX/ТЗ на UI UX.md"};function o(p,l,h,n,d,s){return a(),e("div",null,[...l[0]||(l[0]=[r('<p>Концепция - интерфейс как часть мира. Вся информация, которую игрок получает о мире, должна быть его частью. Нет HUD-а, минимальный интерфейс появляется только при взаимодействии с объектом. Все меню существуют физически в мире игры.</p><h3 id="hud-только-при-взаимодеиствии" tabindex="-1">HUD - только при взаимодействии <a class="header-anchor" href="#hud-только-при-взаимодеиствии" aria-label="Permalink to “HUD - только при взаимодействии”">​</a></h3><ul><li>кнопки-подсказки при взаимодействии с объектом</li><li>названия объектов, с которыми можно взаимодействовать</li><li>иконка действия рядом с названием</li><li>возможность открыть справку с разбором механик при взаимодействии с объектом</li></ul><h5 id="улеи" tabindex="-1">Улей <a class="header-anchor" href="#улеи" aria-label="Permalink to “Улей”">​</a></h5><p>Минимальные индикаторы, когда открыт улей: количество пчел, наполнение рамок медом, векторные иконки в одном стиле, что-то вроде: ───────────────────────────────────── [ИКОНКА ПЧЕЛЫ] 24 / 30 | [🍯] 8/10 ─────────────────────────────────────</p><h5 id="уведомления" tabindex="-1">Уведомления <a class="header-anchor" href="#уведомления" aria-label="Permalink to “Уведомления”">​</a></h5><p>В правом верхнем углу появляются короткие сообщения типа &quot;Мед собран +3&quot;, &quot;Новая цель: проверить медоносы&quot;, &quot;Пчелы забеспокоились!&quot;. Исчезают через 2 секунды</p><h3 id="книга-знании-кодекс-журнал-с-квестами-индикаторы-состояния-пчел" tabindex="-1">Книга знаний (кодекс), журнал с квестами, индикаторы состояния пчел <a class="header-anchor" href="#книга-знании-кодекс-журнал-с-квестами-индикаторы-состояния-пчел" aria-label="Permalink to “Книга знаний (кодекс), журнал с квестами, индикаторы состояния пчел”">​</a></h3><p>В мастерской на столе лежит старая потрепаная книга. Игрок подходит, нажимает Е - открывается интерфейс книги. Нужна 3д модель. В книге переворачиваются страницы, на страницах различная информация типа:</p><p>┌──────────────┐ │ |<br> │ ГЛАВА 1: ПЧЕЛЫ |<br> │ • Типы пчел │ │ • Здоровье │ │ • Размножение | │ │ │ ГЛАВА 2: ЦВЕТЫ | │ • Луговые │<br> │ • Лесные │ │ • Редкие │ │ │ └──────────────┘<br> Шрифт рукописный. страницы стилизованы под бумагу, рисунки/наброски пчел и цветов как в старых энциклопедиях, анимация переворотов страниц, уголки страниц загнуты/потерты, торчит закладка (быстрая навигация).</p><p>Функциональные разделы книги:</p><ol><li>Пчелы: энциклопедия типов пчел, их параметры, болезни</li><li>Цветы: какие цветы где растут, какую пыльцу дают</li><li>Оборудование: описание ульев, инструментов, улучшений</li><li>Заметки деда: история, лор, советы (нарратив)</li><li>Квесты/цели: заметки персонажа (персонаж планирует себе цели, отмечает прогресс)</li><li>Статистика: сколько меда собрано, дней прошло и так далее</li></ol><p>Необходимо сделать:</p><ul><li>шаблон страницы (фоновый слой с текстурой)</li><li>набор иконок для всех типов пчел, цветов, ресурсов</li><li>шрифты: основной рукописный, дополнительный печатный</li><li>элементы: заголовки, буквицы, разделители, рамки для иллюстраций</li><li>анимация перелистывания</li></ul><h3 id="инвентарь-зона-хранения-в-мастерскои" tabindex="-1">Инвентарь - зона хранения в мастерской <a class="header-anchor" href="#инвентарь-зона-хранения-в-мастерскои" aria-label="Permalink to “Инвентарь - зона хранения в мастерской”">​</a></h3><p>У игрока нет портативного инвентаря, он может носить с собой ограниченное количество инструментов (на поясе, в руках). Основной инвентарь:</p><ul><li>ящик с инструментами в мастерской: для мелких предметов (инструменты, расходники)</li><li>стеллаж с банками: для хранения меда и продуктов</li><li>верстак: для крафта и улучшений</li></ul><p>Ящик. Физический объект в мастерской. При взаимодействии открывается UI, стилизованый под открытый ящик. Отделения ящика визуально разделены деревянными перегородками. Предметы лежат как в настоящем ящике (немного под углом, в беспорядке). При наведении показывают название.</p><p>Стеллаж. Игрок подходит к стеллажу, видит полки с банками меда. При взаимодействии камера приближается, и игрок может:</p><ul><li>посмотреть сколько меда каждого сорта (подписаны банки, интерфейс показывает количество)</li><li>взять банку (для действий вроде продажи и перемещения)</li><li>поставить банку (сохранить) Визуально это реальные 3Д-банки на полках, а не иконки. Количество меда можно определить количеством банок и уровнем наполнения. Также количество меда подсчитывается в журнале.</li></ul><p>Верстак для крафта. Стол с инструментами и чертежами. UI открывается как разложенный чертеж. Чертеж выглядит как старая схема с рукописными пометками.</p><h3 id="иконки" tabindex="-1">Иконки <a class="header-anchor" href="#иконки" aria-label="Permalink to “Иконки”">​</a></h3><p>Векторные иконки с тонкими линиями (1.5-2 пкс), скругленные углы, в едином стиле:</p><ul><li>пчела (общая)</li><li>рабочая пчела/трутень/королева</li><li>специализации рабочих пчел (есть в списке)</li><li>воск/пыльца/прополис</li><li>цветы (разные виды)</li><li>инструменты: дымарь, стамеска, щетка</li><li>монета/продажа</li><li>часы/время</li><li>погода (солнце/дождь/ветер)</li><li>здоровье/болезнь</li><li>квест</li><li>книга/кодекс</li></ul>',24)])])}const u=i(t,[["render",o]]);export{c as __pageData,u as default};
